module parallel_load_register(CLK, RST, LOAD_EN, D, Q);
input CLK, RST, LOAD_EN;
input [3:0] D;
output [3:0] Q;
reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Q <= 0;
    else if (LOAD_EN)
        Q <= D;
end

endmodule
